for target in $(cat target.txt);do jq -r '.request.endpoint // empty' OUT-WEB-BIRD/$target/$target-katana.json > OUT-WEB-BIRD/$target/$target-URL-katana && : > OUT-WEB-BIRD/$target/$target-FULL-URLs && cat OUT-WEB-BIRD/$target/$target-URL* >> OUT-WEB-BIRD/$target/$target-FULL-URLs && sort -u OUT-WEB-BIRD/$target/$target-FULL-URLs -o OUT-WEB-BIRD/$target/$target-FULL-URLs && python3 tool-bird-craftjs-v2.py -f OUT-WEB-BIRD/$target/$target-FULL-URLs -o OUT-WEB-BIRD/$target/$target-bird-craftjs --json-output OUT-WEB-BIRD/$target/$target-bird-craftjs.json --scope-domain "${BIRD_SCOPE_DOMAIN:-$target}" --include-subdomains;done
